using NewSmartAIFactory.CompanyApi.Models;using NewSmartAIFactory.CompanyApi.Services;using Npgsql;
namespace NewSmartAIFactory.CompanyApi.Endpoints;
public static class MemoryEndpoints{public static IEndpointRouteBuilder MapMemoryEndpoints(this IEndpointRouteBuilder app){var g=app.MapGroup("/api/memory").WithTags("Memory");g.MapGet("/search",async(string? q,string? scope,int? limit,int? offset,MemoryService s,CancellationToken t)=>Results.Ok(await s.SearchAsync(q,scope,limit??50,t,offset??0)));g.MapGet("/semantic-search",async(string? q,string? scope,int? limit,QdrantMemoryIndexService s,CancellationToken t)=>{if(string.IsNullOrWhiteSpace(q))return Results.BadRequest(new{error="query_required",message="Query q is required."});try{return Results.Ok(await s.SearchAsync(q,scope,limit??10,t));}catch(HttpRequestException ex){return Results.Json(new{error="qdrant_unavailable",message=ex.Message},statusCode:503);}});g.MapPost("/",async(CreateMemoryRequest r,MemoryService s,QdrantMemoryIndexService index,CancellationToken t)=>{if(string.IsNullOrWhiteSpace(r.Scope)||string.IsNullOrWhiteSpace(r.MemoryType)||string.IsNullOrWhiteSpace(r.Title)||string.IsNullOrWhiteSpace(r.Content))return Results.BadRequest(new{error="required_fields",message="Scope, MemoryType, Title, and Content are required."});try{var memory=await s.CreateAsync(r,t);var indexed=true;try{await index.IndexAsync(memory.Id,t);}catch(HttpRequestException){indexed=false;}return Results.Created("/api/memory",new{memory,indexed});}catch(PostgresException ex)when(ex.SqlState==PostgresErrorCodes.ForeignKeyViolation){return Results.BadRequest(new{error="invalid_reference",message="Project or agent reference is invalid."});}});g.MapPost("/reindex",async(int? limit,int? offset,MemoryService s,QdrantMemoryIndexService index,CancellationToken t)=>{var memories=await s.SearchAsync(null,null,limit??200,t,offset??0);var indexed=0;foreach(var memory in memories){try{await index.IndexAsync(memory.Id,t);indexed++;}catch(HttpRequestException){break;}}return Results.Ok(new{requested=memories.Count,indexed,offset=offset??0,nextOffset=(offset??0)+indexed,complete=indexed==memories.Count,collection="company_memory"});});g.MapPatch("/{id:guid}/obsolete",async(Guid id,MemoryService s,QdrantMemoryIndexService index,CancellationToken t)=>{var x=await s.MarkObsoleteAsync(id,t);if(x is null)return Results.NotFound();var removedFromIndex=true;try{await index.DeleteAsync(id,t);}catch(HttpRequestException){removedFromIndex=false;}return Results.Ok(new{memory=x,removedFromIndex});});g.MapGet("/qdrant/health",async(QdrantMemoryIndexService s,CancellationToken t)=>{try{return Results.Ok(new{collection="company_memory",healthy=await s.IsHealthyAsync(t)});}catch(HttpRequestException ex){return Results.Json(new{collection="company_memory",healthy=false,error=ex.Message},statusCode:503);}});g.MapPost("/{id:guid}/index",async(Guid id,QdrantMemoryIndexService s,CancellationToken t)=>{try{var x=await s.IndexAsync(id,t);return x is null?Results.NotFound():Results.Ok(new{indexed=true,memory=x,collection="company_memory"});}catch(HttpRequestException ex){return Results.Json(new{error="qdrant_unavailable",message=ex.Message},statusCode:503);}});return app;}}
